  const hashtags = text.match(hashtagRegex) || [];

  // Extract mentions
  const mentionRegex = /@(\w+)/g;
  const mentions = text.match(mentionRegex) || [];

  // Extract URLs
  const urlRegex = /https?:\/\/[^\s]+/g;
  const urls = text.match(urlRegex) || [];

  return { hashtags, mentions, urls };
}

