// 3. Private properties pattern
function createPrivateObject() {
  const privateData = new WeakMap();

  class PrivateObject {
    constructor(value) {
      privateData.set(this, { value });
    }

    get value() {
      return privateData.get(this).value;
    }

    set value(newValue) {
      privateData.get(this).value = newValue;
    }
  }

  return PrivateObject;
}

const PrivateClass = createPrivateObject();
const instance = new PrivateClass('secret');
console.log(instance.value); // 'secret'

// 4. Observable properties
function createObservable(obj, onChange) {
  return new Proxy(obj, {
    set(target, prop, value) {
      const oldValue = target[prop];
      target[prop] = value;
      onChange(prop, oldValue, value);
      return true;
    }
  });
}

const observable = createObservable({ x: 1 }, (prop, oldVal, newVal) => {
  console.log(`${prop} changed from ${oldVal} to ${newVal}`);
});

observable.x = 2; // Logs: x changed from 1 to 2

// 5. Deep clone with descriptors
function deepCloneWithDescriptors(obj) {
  if (obj === null || typeof obj !== 'object') {
    return obj;
  }

  if (Array.isArray(obj)) {
    return obj.map(item => deepCloneWithDescriptors(item));
  }

  const clone = Object.create(
    Object.getPrototypeOf(obj),
    Object.getOwnPropertyDescriptors(obj)
  );

  for (const key of Object.keys(clone)) {
    clone[key] = deepCloneWithDescriptors(clone[key]);
  }

  return clone;
}

// 6. Mixin pattern
const canEat = {
  eat(food) {
    console.log(`Eating ${food}`);
    this.energy += 10;
  }
};

const canSleep = {
  sleep() {
    console.log('Sleeping');
    this.energy += 20;
  }
};

function mixin(target, ...sources) {
  sources.forEach(source => {
    Object.defineProperties(
      target,
      Object.getOwnPropertyDescriptors(source)
    );
  });
  return target;
}

class Animal {
  constructor() {
    this.energy = 0;
  }
}

mixin(Animal.prototype, canEat, canSleep);

