// Memory leak examples and prevention

// 1. Forgotten timer
function createLeak() {
  const data = new Array(1000000).fill('*');
  // This keeps 'data' in memory forever
  setInterval(() => {
    console.log(data.length);
  }, 1000);
}

// Fix: Clear interval
function createFixed() {
  const data = new Array(1000000).fill('*');
  const intervalId = setInterval(() => {
    console.log(data.length);
  }, 1000);

  // Clear when done
  setTimeout(() => {
    clearInterval(intervalId);
    console.log('Interval cleared');
  }, 5000);
}

// 2. DOM reference leak
function domLeakExample() {
  const elements = [];
  for(let i = 0; i < 1000; i++) {
    const element = document.createElement('div');
    document.body.appendChild(element);
    elements.push(element); // Keeps reference
  }
  // Even if removed from DOM, elements array keeps them in memory
}

// Fix: Remove references
function domFixedExample() {
  for(let i = 0; i < 1000; i++) {
    const element = document.createElement('div');
    document.body.appendChild(element);
  }
  // No array reference = garbage collectable when removed
}

