// Basic decorator implementation
// Note: Requires Babel/TypeScript with decorator support enabled

// Class decorator
function sealed(constructor) {
  Object.seal(constructor);
  Object.seal(constructor.prototype);
}

// Method decorator
function log(target, name, descriptor) {
  const original = descriptor.value;

  descriptor.value = function(...args) {
    console.log(`Calling ${name} with args:`, args);
    const result = original.apply(this, args);
    console.log(`Result: ${result}`);
    return result;
  };

  return descriptor;
}

// Property decorator
function readonly(target, name, descriptor) {
  descriptor.writable = false;
  return descriptor;
}

// Decorator factory (returns decorator)
function validate(type) {
  return function(target, name, descriptor) {
    const original = descriptor.value;

    descriptor.value = function(value) {
      if (typeof value !== type) {
        throw new TypeError(`Expected ${type}, got ${typeof value}`);
      }
      return original.call(this, value);
    };

    return descriptor;
  };
}

// Using decorators
@sealed
class Calculator {
  @readonly
  version = '1.0';

  @log
  add(a, b) {
    return a + b;
  }

  @validate('number')
  multiply(a, b) {
    return a * b;
  }

  // Auto-bind decorator
  @autoBind
  getVersion() {
    return this.version;
  }
}

const calc = new Calculator();
calc.add(2, 3); // Logs: Calling add with args: [2, 3], Result: 5

// calc.version = '2.0'; // Error: Cannot assign to read only property
// calc.multiply('2', 3); // TypeError: Expected number, got string

// Parameter decorator
function required(target, propertyKey, parameterIndex) {
  const existingRequired = Reflect.getOwnMetadata('required', target, propertyKey) || [];
  existingRequired.push(parameterIndex);
  Reflect.defineMetadata('required', existingRequired, target, propertyKey);
}

// Accessor decorator
function configurable(value) {
  return function(target, propertyKey, descriptor) {
    descriptor.configurable = value;
    return descriptor;
  };
}

// Multiple decorators (executed bottom to top)
class User {
  @log
  @validate('string')
  setName(@required name) {
    this.name = name;
  }
}

// Auto-bind implementation
function autoBind(target, name, descriptor) {
  const originalMethod = descriptor.value;

  return {
    configurable: true,
    enumerable: false,
    get() {
      // Bind to instance
      const bound = originalMethod.bind(this);

      // Cache the bound function
      Object.defineProperty(this, name, {
        value: bound,
        configurable: true,
        writable: true
      });

      return bound;
    }
  };
}

// Memoization decorator
function memoize(target, name, descriptor) {
  const original = descriptor.value;
  const cache = new Map();

  descriptor.value = function(...args) {
    const key = JSON.stringify(args);

    if (cache.has(key)) {
      console.log('Returning cached result');
      return cache.get(key);
    }

    const result = original.apply(this, args);
    cache.set(key, result);
    return result;
  };

  return descriptor;
}

class MathOperations {
  @memoize
  fibonacci(n) {
    if (n <= 1) return n;
    return this.fibonacci(n - 1) + this.fibonacci(n - 2);
  }
}

