// Performance comparison
function testTimerPrecision() {
  const results = [];

  // Test setTimeout precision
  let lastTime = performance.now();
  const timeoutTest = setInterval(() => {
    const now = performance.now();
    const diff = now - lastTime;
    results.push({ type: 'setTimeout', diff });
    lastTime = now;
  }, 16); // ~60fps

  setTimeout(() => {
    clearInterval(timeoutTest);

    // Calculate average deviation
    const avgDeviation = results.reduce((sum, r) => sum + Math.abs(r.diff - 16), 0) / results.length;
    console.log(`setTimeout average deviation: ${avgDeviation.toFixed(2)}ms`);
  }, 1000);
}

// Debouncing with setTimeout
function debounce(func, delay) {
  let timeoutId;

  return function(...args) {
    clearTimeout(timeoutId);

    timeoutId = setTimeout(() => {
      func.apply(this, args);
    }, delay);
  };
}

// Throttling with setTimeout
function throttle(func, limit) {
  let inThrottle;

  return function(...args) {
    if (!inThrottle) {
      func.apply(this, args);
      inThrottle = true;

      setTimeout(() => {
        inThrottle = false;
      }, limit);
    }
  };
}

// Using requestAnimationFrame for smooth animations
class SmoothAnimator {
  constructor() {
    this.animations = new Map();
    this.isRunning = false;
  }

  add(id, updateFn) {
    this.animations.set(id, updateFn);
    if (!this.isRunning) {
      this.start();
    }
  }

  remove(id) {
    this.animations.delete(id);
    if (this.animations.size === 0) {
      this.stop();
    }
  }

  start() {
    this.isRunning = true;

    const animate = (timestamp) => {
      if (!this.isRunning) return;

      // Update all animations
      this.animations.forEach(updateFn => {
        updateFn(timestamp);
      });

      requestAnimationFrame(animate);
    };

    requestAnimationFrame(animate);
  }

  stop() {
    this.isRunning = false;
  }
}

