function areAnagrams(str1, str2) {
  // Clean strings
  const cleanStr1 = str1.replace(/[^a-z]/gi, '').toLowerCase();
  const cleanStr2 = str2.replace(/[^a-z]/gi, '').toLowerCase();

  // If lengths are different, they can't be anagrams
  if (cleanStr1.length !== cleanStr2.length) {
    return false;
  }

  // Method 1: Sort and compare
  // const sorted1 = cleanStr1.split('').sort().join('');
  // const sorted2 = cleanStr2.split('').sort().join('');
  // return sorted1 === sorted2;

  // Method 2: Character frequency map
  const charMap = {};

  // Build frequency map for first string
  for (let char of cleanStr1) {
    charMap[char] = (charMap[char] || 0) + 1;
  }

  // Compare with second string
  for (let char of cleanStr2) {
    if (!charMap[char]) {
      return false;
    }
    charMap[char]--;
  }

  return true;
}

