function maxCharacter(str) {
  if (!str || str.length === 0) {
    return '';
  }

  const charMap = {};
  let maxChar = '';
  let maxCount = 0;

  // Build character frequency map
  for (let char of str.toLowerCase()) {
    // Optional: skip spaces
    // if (char === ' ') continue;

    charMap[char] = (charMap[char] || 0) + 1;

    // Update max if current count is greater
    if (charMap[char] > maxCount) {
      maxCount = charMap[char];
      maxChar = char;
    }
  }

  return maxChar;
}

// Alternative: find all max characters
function maxCharacters(str) {
  if (!str || str.length === 0) return [];

  const charMap = {};
  let maxCount = 0;
  const result = [];

  // Build frequency map
  for (let char of str.toLowerCase()) {
    charMap[char] = (charMap[char] || 0) + 1;
    maxCount = Math.max(maxCount, charMap[char]);
  }

  // Find all characters with maxCount
  for (let char in charMap) {
    if (charMap[char] === maxCount) {
      result.push(char);
    }
  }

  return result;
}

