function flattenArray(arr) {
  const result = [];

  // Helper function for recursion
  function flattenHelper(element) {
    if (Array.isArray(element)) {
      for (let item of element) {
        flattenHelper(item);
      }
    } else {
      result.push(element);
    }
  }

  flattenHelper(arr);
  return result;
}

// Using reduce
function flattenArrayReduce(arr) {
  return arr.reduce((acc, val) => 
    Array.isArray(val) ? acc.concat(flattenArrayReduce(val)) : acc.concat(val),
  []);
}

// Using stack (non-recursive)
function flattenArrayStack(arr) {
  const stack = [...arr];
  const result = [];

  while (stack.length) {
    const next = stack.pop();

    if (Array.isArray(next)) {
      stack.push(...next);
    } else {
      result.push(next);
    }
  }

  return result.reverse();
}

// With depth parameter
function flattenArrayDepth(arr, depth = Infinity) {
  if (depth <= 0) return arr.slice();

  return arr.reduce((acc, val) => {
    if (Array.isArray(val) && depth > 0) {
      acc.push(...flattenArrayDepth(val, depth - 1));
    } else {
      acc.push(val);
    }
    return acc;
  }, []);
}

