class Queue {
  constructor() {
    this.items = [];
    this.front = 0; // Optimized version to avoid shift O(n)
    this.rear = 0;
    this.size = 0;
  }

  // Add element to the end
  enqueue(element) {
    this.items[this.rear] = element;
    this.rear++;
    this.size++;
    return this.size;
  }

  // Remove element from the front
  dequeue() {
    if (this.isEmpty()) {
      return null;
    }

    const item = this.items[this.front];
    delete this.items[this.front];
    this.front++;
    this.size--;

    // Reset pointers if queue is empty
    if (this.isEmpty()) {
      this.front = 0;
      this.rear = 0;
    }

    return item;
  }

  // View front element
  peek() {
    if (this.isEmpty()) {
      return null;
    }
    return this.items[this.front];
  }

  // Check if queue is empty
  isEmpty() {
    return this.size === 0;
  }

  // Get queue size
  getSize() {
    return this.size;
  }

  // Clear queue
  clear() {
    this.items = [];
    this.front = 0;
    this.rear = 0;
    this.size = 0;
  }

  // Convert to array
  toArray() {
    return this.items.slice(this.front, this.rear);
  }
}

// Simple array-based queue (less efficient)
