class Stack {
  constructor() {
    this.items = [];
    this.size = 0;
  }

  // Add element to the top
  push(element) {
    this.items.push(element);
    this.size++;
    return this.size;
  }

  // Remove element from the top
  pop() {
    if (this.isEmpty()) {
      return null;
    }
    this.size--;
    return this.items.pop();
  }

  // View top element
  peek() {
    if (this.isEmpty()) {
      return null;
    }
    return this.items[this.size - 1];
  }

  // Check if stack is empty
  isEmpty() {
    return this.size === 0;
  }

  // Get stack size
  getSize() {
    return this.size;
  }

  // Clear stack
  clear() {
    this.items = [];
    this.size = 0;
  }

  // Convert to array
  toArray() {
    return [...this.items];
  }
}

// Stack with max tracking
class MaxStack {
  constructor() {
    this.stack = [];
    this.maxStack = [];
  }

  push(val) {
    this.stack.push(val);

    if (this.maxStack.length === 0 || val >= this.maxStack[this.maxStack.length - 1]) {
      this.maxStack.push(val);
    }
  }

  pop() {
    if (this.stack.length === 0) return null;

    const val = this.stack.pop();

    if (val === this.maxStack[this.maxStack.length - 1]) {
      this.maxStack.pop();
    }

    return val;
  }

  getMax() {
    if (this.maxStack.length === 0) return null;
    return this.maxStack[this.maxStack.length - 1];
  }
}

