function bubbleSort(arr) {
  const n = arr.length;
  let swapped;

  // Outer loop for passes
  for (let i = 0; i < n - 1; i++) {
    swapped = false;

    // Inner loop for comparisons
    // After each pass, largest element bubbles to end
    for (let j = 0; j < n - 1 - i; j++) {
      if (arr[j] > arr[j + 1]) {
        // Swap elements
        [arr[j], arr[j + 1]] = [arr[j + 1], arr[j]];
        swapped = true;
      }
    }

    // If no swaps occurred, array is sorted
    if (!swapped) {
      break;
    }
  }

  return arr;
}

// Recursive bubble sort
function bubbleSortRecursive(arr, n = arr.length) {
  // Base case
  if (n === 1) {
    return arr;
  }

  let swapped = false;

  // One pass of bubble sort
  for (let i = 0; i < n - 1; i++) {
    if (arr[i] > arr[i + 1]) {
      [arr[i], arr[i + 1]] = [arr[i + 1], arr[i]];
      swapped = true;
    }
  }

  // If no swaps, array is sorted
  if (!swapped) {
    return arr;
  }

  // Recur for remaining elements
  return bubbleSortRecursive(arr, n - 1);
}

// Optimized with last swap position
function bubbleSortOptimized(arr) {
  let n = arr.length;
  let newN;

  while (n > 1) {
    newN = 0;

    for (let i = 1; i < n; i++) {
      if (arr[i - 1] > arr[i]) {
        [arr[i - 1], arr[i]] = [arr[i], arr[i - 1]];
        newN = i;
      }
    }

    n = newN; // Last swap position becomes new boundary
  }

  return arr;
}

