function quickSort(arr, left = 0, right = arr.length - 1) {
  if (left < right) {
    // Partition array and get pivot index
    const pivotIndex = partition(arr, left, right);

    // Recursively sort elements before and after partition
    quickSort(arr, left, pivotIndex - 1);
    quickSort(arr, pivotIndex + 1, right);
  }

  return arr;
}

function partition(arr, left, right) {
  // Choose pivot (using last element)
  const pivot = arr[right];
  let i = left - 1; // Index of smaller element

  for (let j = left; j < right; j++) {
    // If current element is smaller than or equal to pivot
    if (arr[j] <= pivot) {
      i++; // Increment index of smaller element
      [arr[i], arr[j]] = [arr[j], arr[i]]; // Swap
    }
  }

  // Place pivot in correct position
  [arr[i + 1], arr[right]] = [arr[right], arr[i + 1]];
  return i + 1;
}

// Quick sort with different pivot strategies
function quickSortMiddlePivot(arr, left = 0, right = arr.length - 1) {
  if (left >= right) return arr;

  // Choose middle element as pivot
  const mid = Math.floor((left + right) / 2);
  const pivot = arr[mid];

  let i = left;
  let j = right;

  while (i <= j) {
    while (arr[i] < pivot) i++;
    while (arr[j] > pivot) j--;

    if (i <= j) {
      [arr[i], arr[j]] = [arr[j], arr[i]];
      i++;
      j--;
    }
  }

  // Recursively sort partitions
  if (left < j) quickSortMiddlePivot(arr, left, j);
  if (i < right) quickSortMiddlePivot(arr, i, right);

  return arr;
}

// Quick sort with random pivot (good for avoiding worst-case)
function quickSortRandomPivot(arr, left = 0, right = arr.length - 1) {
  if (left < right) {
    // Random pivot between left and right
    const randomIndex = Math.floor(Math.random() * (right - left + 1)) + left;

    // Move random pivot to the end
    [arr[randomIndex], arr[right]] = [arr[right], arr[randomIndex]];

    const pivotIndex = partition(arr, left, right);
    quickSortRandomPivot(arr, left, pivotIndex - 1);
    quickSortRandomPivot(arr, pivotIndex + 1, right);
  }

  return arr;
}

