console.log(quickSortMiddlePivot([10, 7, 8, 9, 1, 5])); // [1, 5, 7, 8, 9, 10]

function longestWord(str) {
  if (!str || str.trim().length === 0) {
    return '';
  }

  // Clean string and split into words
  // \w matches alphanumeric characters and underscore
  const words = str.match(/\b\w+\b/g) || [];

  if (words.length === 0) {
    return '';
  }

  let longest = words[0];

  for (let word of words) {
    if (word.length > longest.length) {
      longest = word;
    }
  }

  return longest;
}

// Return all longest words
function longestWords(str) {
  if (!str || str.trim().length === 0) {
    return [];
  }

  const words = str.match(/\b\w+\b/g) || [];

  if (words.length === 0) {
    return [];
  }

  // Find max length
  let maxLength = 0;
  for (let word of words) {
    maxLength = Math.max(maxLength, word.length);
  }

  // Find all words with max length
  return words.filter(word => word.length === maxLength);
}

// Using reduce
function longestWordReduce(str) {
  const words = str.match(/\b\w+\b/g) || [];

  return words.reduce((longest, current) => 
    current.length > longest.length ? current : longest
  , '');
}

