function capitalizeWords(str) {
  if (!str || str.trim().length === 0) {
    return '';
  }

  // Split on whitespace
  const words = str.split(/\s+/);

  const capitalized = words.map(word => {
    if (word.length === 0) {
      return '';
    }

    // Capitalize first letter, keep rest as is
    return word.charAt(0).toUpperCase() + word.slice(1).toLowerCase();
  });

  return capitalized.join(' ');
}

// Without using split/map (for performance)
function capitalizeWordsLoop(str) {
  if (!str || str.trim().length === 0) {
    return '';
  }

  let result = '';
  let capitalizeNext = true;

  for (let i = 0; i < str.length; i++) {
    const char = str[i];

    if (capitalizeNext && /[a-zA-Z]/.test(char)) {
      result += char.toUpperCase();
      capitalizeNext = false;
    } else {
      result += char.toLowerCase();
    }

    // Check if next character should be capitalized
    if (/\s/.test(char)) {
      capitalizeNext = true;
    }
  }

  return result;
}

// Using regex with replace
function capitalizeWordsRegex(str) {
  return str.replace(/\b\w/g, char => char.toUpperCase());
}

