  , 0);
}

// Count each vowel separately
function countEachVowel(str) {
  if (!str || str.length === 0) {
    return { a: 0, e: 0, i: 0, o: 0, u: 0 };
  }

  const lowerStr = str.toLowerCase();
  const vowels = { a: 0, e: 0, i: 0, o: 0, u: 0 };

  for (let char of lowerStr) {
    if (vowels.hasOwnProperty(char)) {
      vowels[char]++;
    }
  }

  return vowels;
}

