function isPrime(n) {
  // Numbers less than 2 are not prime
  if (n < 2) {
    return false;
  }

  // Check for 2 and 3
  if (n === 2 || n === 3) {
    return true;
  }

  // Even numbers and multiples of 3 are not prime (except 2 and 3)
  if (n % 2 === 0 || n % 3 === 0) {
    return false;
  }

  // Check divisibility from 5 to sqrt(n)
  // All primes greater than 3 can be written as 6k ± 1
  for (let i = 5; i * i <= n; i += 6) {
    if (n % i === 0 || n % (i + 2) === 0) {
      return false;
    }
  }

  return true;
}

// Simple implementation
function isPrimeSimple(n) {
  if (n < 2) return false;

  for (let i = 2; i <= Math.sqrt(n); i++) {
    if (n % i === 0) {
      return false;
    }
  }

  return true;
}

// Generate list of primes up to n (Sieve of Eratosthenes)
function generatePrimes(limit) {
  if (limit < 2) return [];

  // Create array from 0 to limit, initially all true
  const sieve = new Array(limit + 1).fill(true);
  sieve[0] = sieve[1] = false;

  // Mark non-primes
  for (let i = 2; i * i <= limit; i++) {
    if (sieve[i]) {
      // Mark multiples of i as non-prime
      for (let j = i * i; j <= limit; j += i) {
        sieve[j] = false;
      }
    }
  }

  // Collect primes
  const primes = [];
  for (let i = 2; i <= limit; i++) {
    if (sieve[i]) {
      primes.push(i);
    }
  }

  return primes;
}

