function removeDuplicates(arr) {
  if (!arr || arr.length === 0) {
    return [];
  }

  // Method 1: Using Set (simplest, but order not guaranteed in older JS)
  // return [...new Set(arr)];

  // Method 2: Using filter with indexOf (preserves order)
  return arr.filter((item, index) => arr.indexOf(item) === index);
}

// Using reduce
function removeDuplicatesReduce(arr) {
  if (!arr || arr.length === 0) {
    return [];
  }

  return arr.reduce((unique, item) => {
    if (!unique.includes(item)) {
      unique.push(item);
    }
    return unique;
  }, []);
}

// Using Map (preserves order, O(n) time)
function removeDuplicatesMap(arr) {
  if (!arr || arr.length === 0) {
    return [];
  }

  const seen = new Map();
  const result = [];

  for (let item of arr) {
    if (!seen.has(item)) {
      seen.set(item, true);
      result.push(item);
    }
  }

  return result;
}

// For arrays of objects with key
function removeDuplicatesByKey(arr, key) {
  if (!arr || arr.length === 0) {
    return [];
  }

  const seen = new Set();
  return arr.filter(item => {
    const value = item[key];
    if (seen.has(value)) {
      return false;
    }
    seen.add(value);
    return true;
  });
}

