function mergeSortedArrays(arr1, arr2) {
  const merged = [];
  let i = 0; // Pointer for arr1
  let j = 0; // Pointer for arr2

  // Compare elements from both arrays
  while (i < arr1.length && j < arr2.length) {
    if (arr1[i] <= arr2[j]) {
      merged.push(arr1[i]);
      i++;
    } else {
      merged.push(arr2[j]);
      j++;
    }
  }

  // Add remaining elements from arr1
  while (i < arr1.length) {
    merged.push(arr1[i]);
    i++;
  }

  // Add remaining elements from arr2
  while (j < arr2.length) {
    merged.push(arr2[j]);
    j++;
  }

  return merged;
}

// Merge without duplicates
function mergeSortedArraysUnique(arr1, arr2) {
  const merged = [];
  let i = 0;
  let j = 0;
  let lastAdded = null;

  while (i < arr1.length || j < arr2.length) {
    let toAdd;

    // Determine which element to add next
    if (i >= arr1.length) {
      toAdd = arr2[j++];
    } else if (j >= arr2.length) {
      toAdd = arr1[i++];
    } else if (arr1[i] <= arr2[j]) {
      toAdd = arr1[i++];
    } else {
      toAdd = arr2[j++];
    }

    // Add if not duplicate
    if (toAdd !== lastAdded) {
      merged.push(toAdd);
      lastAdded = toAdd;
    }
  }

  return merged;
}

// Merge k sorted arrays
function mergeKSortedArrays(arrays) {
  // Simple approach: flatten and sort
  // return arrays.flat().sort((a, b) => a - b);

  // Efficient approach: merge pairs
  if (arrays.length === 0) return [];
  if (arrays.length === 1) return arrays[0];

  let result = arrays[0];

  for (let i = 1; i < arrays.length; i++) {
    result = mergeSortedArrays(result, arrays[i]);
  }

  return result;
}

