function throttle(func, limit) {
  let lastFunc;
  let lastRan;

  return function(...args) {
    const context = this;

    if (!lastRan) {
      // First execution
      func.apply(context, args);
      lastRan = Date.now();
    } else {
      clearTimeout(lastFunc);

      lastFunc = setTimeout(() => {
        if (Date.now() - lastRan >= limit) {
          func.apply(context, args);
          lastRan = Date.now();
        }
      }, limit - (Date.now() - lastRan));
    }
  };
}

// Enhanced throttle with leading/trailing options
function throttleEnhanced(func, limit, options = {}) {
  let timeout = null;
  let lastRan = 0;
  let result;

  const { leading = true, trailing = true } = options;

  const throttled = function(...args) {
    const context = this;
    const now = Date.now();

    if (!lastRan && !leading) {
      lastRan = now;
    }

    const remaining = limit - (now - lastRan);

    if (remaining <= 0 || remaining > limit) {
      if (timeout) {
        clearTimeout(timeout);
        timeout = null;
      }

      lastRan = now;
      result = func.apply(context, args);
    } else if (!timeout && trailing) {
      timeout = setTimeout(() => {
        lastRan = leading ? Date.now() : 0;
        timeout = null;
        result = func.apply(context, args);
      }, remaining);
    }

    return result;
  };

  throttled.cancel = function() {
    clearTimeout(timeout);
    timeout = null;
    lastRan = 0;
  };

  throttled.flush = function() {
    if (timeout) {
      clearTimeout(timeout);
      timeout = null;
      lastRan = leading ? Date.now() : 0;
      return func.apply(this, arguments);
    }
  };

  return throttled;
}

// Simple throttle using timestamp
function throttleSimple(func, limit) {
  let inThrottle;

  return function(...args) {
    const context = this;

    if (!inThrottle) {
      func.apply(context, args);
      inThrottle = true;

      setTimeout(() => {
        inThrottle = false;
      }, limit);
    }
  };
}

