function curry(fn) {
  return function curried(...args) {
    // If enough arguments have been provided, call original function
    if (args.length >= fn.length) {
      return fn.apply(this, args);
    }

    // Otherwise, return a new function that collects remaining arguments
    return function(...nextArgs) {
      return curried.apply(this, args.concat(nextArgs));
    };
  };
}

// With placeholder support
function curryWithPlaceholder(fn) {
  const placeholder = {}; // Unique placeholder object

  function curried(...args) {
    // Check if we have enough non-placeholder arguments
    const actualArgs = args.slice(0, fn.length);
    const hasPlaceholder = actualArgs.some(arg => arg === placeholder);

    if (actualArgs.length >= fn.length && !hasPlaceholder) {
      return fn.apply(this, actualArgs);
    }

    return function(...nextArgs) {
      // Replace placeholders with actual arguments
      const mergedArgs = [];
      let argsIndex = 0;
      let nextArgsIndex = 0;

      while (argsIndex < args.length && mergedArgs.length < fn.length) {
        if (args[argsIndex] === placeholder && nextArgsIndex < nextArgs.length) {
          mergedArgs.push(nextArgs[nextArgsIndex]);
          nextArgsIndex++;
        } else {
          mergedArgs.push(args[argsIndex]);
        }
        argsIndex++;
      }

      // Add remaining nextArgs
      while (mergedArgs.length < fn.length && nextArgsIndex < nextArgs.length) {
        mergedArgs.push(nextArgs[nextArgsIndex]);
        nextArgsIndex++;
      }

      return curried.apply(this, mergedArgs);
    };
  }

  // Add placeholder property to curried function
  curried.placeholder = placeholder;
  return curried;
}

// Auto-curry: curry any function to accept arguments one at a time
function autoCurry(fn, arity = fn.length) {
  return function curried(...args) {
    if (args.length >= arity) {
      return fn.apply(this, args);
    }

    return function(...nextArgs) {
      return curried.apply(this, args.concat(nextArgs));
    };
  };
}

