function memoize(fn) {
  const cache = new Map();

  return function(...args) {
    // Create cache key from arguments
    const key = JSON.stringify(args);

    if (cache.has(key)) {
      return cache.get(key);
    }

    const result = fn.apply(this, args);
    cache.set(key, result);
    return result;
  };
}

// With cache size limit
function memoizeWithLimit(fn, limit = 100) {
  const cache = new Map();
  const keys = [];

  return function(...args) {
    const key = JSON.stringify(args);

    if (cache.has(key)) {
      // Move key to end (most recently used)
      const keyIndex = keys.indexOf(key);
      keys.splice(keyIndex, 1);
      keys.push(key);

      return cache.get(key);
    }

    const result = fn.apply(this, args);
    cache.set(key, result);
    keys.push(key);

    // Remove oldest entry if cache exceeds limit
    if (keys.length > limit) {
      const oldestKey = keys.shift();
      cache.delete(oldestKey);
    }

    return result;
  };
}

// For functions with object arguments (using WeakMap)
function memoizeObjectArgs(fn) {
  const cache = new WeakMap();

  return function(objArg, ...restArgs) {
    if (!cache.has(objArg)) {
      cache.set(objArg, new Map());
    }

    const innerCache = cache.get(objArg);
    const key = JSON.stringify(restArgs);

    if (innerCache.has(key)) {
      return innerCache.get(key);
    }

    const result = fn.apply(this, [objArg, ...restArgs]);
    innerCache.set(key, result);
    return result;
  };
}

// Memoize with custom resolver
function memoizeWithResolver(fn, resolver = (...args) => JSON.stringify(args)) {
  const cache = new Map();

  return function(...args) {
    const key = resolver.apply(this, args);

    if (cache.has(key)) {
      return cache.get(key);
    }

    const result = fn.apply(this, args);
    cache.set(key, result);
    return result;
  };
}

