// Fibonacci with memoization
const memoizedFib = memoize(function fib(n) {
  if (n <= 1) return n;
  return memoizedFib(n - 1) + memoizedFib(n - 2);
});

console.log(memoizedFib(10)); // 55
console.log(memoizedFib(40)); // 102334155 (fast due to memoization)

Function.prototype.myBind = function(context, ...bindArgs) {
  const originalFunc = this;

  const boundFunction = function(...callArgs) {
    // Determine context: if called with new, use new instance
    const isNewCall = this instanceof boundFunction;
    const thisContext = isNewCall ? this : context;

    return originalFunc.apply(thisContext, bindArgs.concat(callArgs));
  };

  // Preserve prototype chain for new operator
  if (originalFunc.prototype) {
    // Use Object.create to avoid mutating original prototype
    boundFunction.prototype = Object.create(originalFunc.prototype);
  }

  // Preserve function properties
  boundFunction.length = Math.max(0, originalFunc.length - bindArgs.length);

  return boundFunction;
};

// Alternative implementation with more complete feature set
function customBind(fn, context, ...bindArgs) {
  function bound(...callArgs) {
    // Check if called with new
    const isConstructorCall = new.target !== undefined;
    const thisBinding = isConstructorCall ? this : context;

    return fn.apply(thisBinding, bindArgs.concat(callArgs));
  }

  // Copy prototype for inheritance
  if (fn.prototype) {
    // Using Object.setPrototypeOf instead of direct assignment
    Object.setPrototypeOf(bound.prototype, fn.prototype);
  }

  // Copy function properties
  const descriptor = Object.getOwnPropertyDescriptor(fn, 'length');
  if (descriptor) {
    Object.defineProperty(bound, 'length', {
      value: Math.max(0, fn.length - bindArgs.length),
      writable: false,
      enumerable: false,
      configurable: true
    });
  }

  // Copy name property
  Object.defineProperty(bound, 'name', {
    value: `bound ${fn.name}`,
    writable: false,
    enumerable: false,
    configurable: true
  });

  return bound;
}

