function intersection(...arrays) {
  if (arrays.length === 0) {
    return [];
  }

  if (arrays.length === 1) {
    return [...new Set(arrays[0])]; // Return unique elements
  }

  // Start with first array
  let result = [...new Set(arrays[0])];

  // Intersect with each subsequent array
  for (let i = 1; i < arrays.length; i++) {
    const currentSet = new Set(arrays[i]);
    result = result.filter(item => currentSet.has(item));
  }

  return result;
}

// Using reduce
function intersectionReduce(...arrays) {
  if (arrays.length === 0) return [];

  return arrays
    .map(arr => [...new Set(arr)]) // Remove duplicates from each array
    .reduce((acc, current) => 
      acc.filter(item => current.includes(item))
    );
}

// For two arrays (simple case)
function intersectionTwo(arr1, arr2) {
  const set2 = new Set(arr2);
  return [...new Set(arr1.filter(item => set2.has(item)))];
}

// Find common elements with frequency
function intersectionWithCount(...arrays) {
  if (arrays.length === 0) return [];

  const frequencyMap = new Map();

  // Count occurrences across all arrays
  arrays.forEach(arr => {
    const uniqueInArr = new Set(arr);

    uniqueInArr.forEach(item => {
      frequencyMap.set(item, (frequencyMap.get(item) || 0) + 1);
    });
  });

  // Items present in all arrays
  const result = [];
  frequencyMap.forEach((count, item) => {
    if (count === arrays.length) {
      result.push(item);
    }
  });

  return result;
}

